/**
 * Modern Loader & Modal Components
 * Professional loading indicators and modal dialogs
 */

class LoadingOverlay {
    constructor(message = 'Loading...', subMessage = '') {
        this.message = message;
        this.subMessage = subMessage;
        this.overlay = null;
    }

    show(loaderType = 'ring') {
        if (this.overlay) return; // Already showing

        const overlay = document.createElement('div');
        overlay.className = 'loading-overlay';
        overlay.id = 'loadingOverlay';

        const content = document.createElement('div');
        content.className = 'loading-overlay-content';

        const loaderHTML = this._getLoaderHTML(loaderType);
        content.innerHTML = loaderHTML;

        const heading = document.createElement('h2');
        heading.textContent = this.message;
        content.appendChild(heading);

        if (this.subMessage) {
            const subMsg = document.createElement('p');
            subMsg.textContent = this.subMessage;
            content.appendChild(subMsg);
        }

        overlay.appendChild(content);
        document.body.appendChild(overlay);
        this.overlay = overlay;
    }

    hide() {
        if (this.overlay) {
            this.overlay.remove();
            this.overlay = null;
        }
    }

    _getLoaderHTML(type) {
        const loaders = {
            'ring': `
                <div class="loader-ring">
                    <div></div>
                    <div></div>
                    <div></div>
                </div>
            `,
            'dots': `
                <div class="loader-dots">
                    <span></span>
                    <span></span>
                    <span></span>
                </div>
            `,
            'wave': `
                <div class="loader-wave">
                    <span></span>
                    <span></span>
                    <span></span>
                    <span></span>
                    <span></span>
                </div>
            `,
            'grid': `
                <div class="loader-grid">
                    ${Array(9).fill(0).map(() => '<span></span>').join('')}
                </div>
            `,
            'bar': `
                <div class="loader-bar"></div>
            `
        };

        return loaders[type] || loaders['ring'];
    }
}

class ConfirmDialog {
    constructor(title, message, onConfirm, onCancel = null) {
        this.title = title;
        this.message = message;
        this.onConfirm = onConfirm;
        this.onCancel = onCancel;
        this.dialog = null;
    }

    show() {
        const dialog = document.createElement('div');
        dialog.className = 'confirm-dialog-overlay';
        dialog.id = 'confirmDialog';

        dialog.innerHTML = `
            <div class="confirm-dialog modal-enter">
                <div class="confirm-header">
                    <h2>${this.title}</h2>
                    <button class="confirm-close">&times;</button>
                </div>
                <div class="confirm-body">
                    <p>${this.message}</p>
                </div>
                <div class="confirm-footer">
                    <button class="btn btn-secondary confirm-cancel">Cancel</button>
                    <button class="btn btn-primary confirm-ok">Confirm</button>
                </div>
            </div>
        `;

        const closeBtn = dialog.querySelector('.confirm-close');
        const cancelBtn = dialog.querySelector('.confirm-cancel');
        const okBtn = dialog.querySelector('.confirm-ok');

        const cleanup = () => {
            dialog.remove();
            this.dialog = null;
        };

        closeBtn.addEventListener('click', () => {
            if (this.onCancel) this.onCancel();
            cleanup();
        });

        cancelBtn.addEventListener('click', () => {
            if (this.onCancel) this.onCancel();
            cleanup();
        });

        okBtn.addEventListener('click', () => {
            this.onConfirm();
            cleanup();
        });

        document.body.appendChild(dialog);
        this.dialog = dialog;
    }

    hide() {
        if (this.dialog) {
            this.dialog.remove();
            this.dialog = null;
        }
    }
}

class Toast {
    static show(message, type = 'info', duration = 3000) {
        const container = document.getElementById('toastContainer') || this._createContainer();

        const toast = document.createElement('div');
        toast.className = `toast toast-${type} animate-slide-in-right`;
        toast.innerHTML = `
            <i class="fas fa-${this._getIcon(type)}"></i>
            <span>${message}</span>
            <button class="toast-close">&times;</button>
        `;

        container.appendChild(toast);

        const closeBtn = toast.querySelector('.toast-close');
        const remove = () => toast.remove();

        closeBtn.addEventListener('click', remove);
        setTimeout(remove, duration);
    }

    static _createContainer() {
        const container = document.createElement('div');
        container.id = 'toastContainer';
        container.className = 'toast-container';
        document.body.appendChild(container);
        return container;
    }

    static _getIcon(type) {
        const icons = {
            'success': 'check-circle',
            'error': 'exclamation-circle',
            'warning': 'warning',
            'info': 'info-circle'
        };
        return icons[type] || 'info-circle';
    }
}

// Global convenience functions
window.showLoader = (msg, sub, type) => {
    window._loader = new LoadingOverlay(msg, sub);
    window._loader.show(type || 'ring');
};

window.hideLoader = () => {
    if (window._loader) window._loader.hide();
};

window.confirm = (title, msg, onOk, onCancel) => {
    const dialog = new ConfirmDialog(title, msg, onOk, onCancel);
    dialog.show();
};

window.toast = (msg, type, duration) => {
    Toast.show(msg, type || 'info', duration);
};

/**
 * Modern UI Utilities & Enhancements
 * Professional animations, interactions, and form handling
 */

class FormValidator {
    constructor(formSelector) {
        this.form = document.querySelector(formSelector);
        this.fields = new Map();
    }

    addField(fieldName, validators = []) {
        this.fields.set(fieldName, validators);
    }

    validate() {
        let isValid = true;
        this.fields.forEach((validators, fieldName) => {
            const field = this.form.querySelector(`[name="${fieldName}"]`);
            if (!field) return;

            const hasError = validators.some(validator => !validator.test(field.value));
            if (hasError) {
                this.showError(field);
                isValid = false;
            } else {
                this.clearError(field);
            }
        });
        return isValid;
    }

    showError(field) {
        field.classList.add('error');
        const errorDiv = document.createElement('div');
        errorDiv.className = 'field-error';
        errorDiv.textContent = 'This field is invalid';
        const existing = field.nextElementSibling;
        if (!existing || !existing.classList.contains('field-error')) {
            field.insertAdjacentElement('afterend', errorDiv);
        }
    }

    clearError(field) {
        field.classList.remove('error');
        const errorDiv = field.nextElementSibling;
        if (errorDiv && errorDiv.classList.contains('field-error')) {
            errorDiv.remove();
        }
    }
}

class DataTable {
    constructor(tableSelector) {
        this.table = document.querySelector(tableSelector);
        this.currentSort = { column: 0, direction: 'asc' };
        this.init();
    }

    init() {
        if (!this.table) return;

        const headers = this.table.querySelectorAll('th');
        headers.forEach((header, index) => {
            header.style.cursor = 'pointer';
            header.addEventListener('click', () => this.sort(index));
        });
    }

    sort(columnIndex) {
        const tbody = this.table.querySelector('tbody');
        const rows = Array.from(tbody.querySelectorAll('tr'));

        if (this.currentSort.column === columnIndex) {
            this.currentSort.direction = this.currentSort.direction === 'asc' ? 'desc' : 'asc';
        } else {
            this.currentSort.column = columnIndex;
            this.currentSort.direction = 'asc';
        }

        rows.sort((a, b) => {
            const aValue = a.children[columnIndex].textContent;
            const bValue = b.children[columnIndex].textContent;

            if (!isNaN(aValue) && !isNaN(bValue)) {
                return this.currentSort.direction === 'asc' 
                    ? aValue - bValue 
                    : bValue - aValue;
            }

            const comparison = aValue.localeCompare(bValue);
            return this.currentSort.direction === 'asc' ? comparison : -comparison;
        });

        tbody.innerHTML = '';
        rows.forEach(row => tbody.appendChild(row));
    }
}

class PageTransition {
    static fadeOut(duration = 300) {
        const page = document.querySelector('.page-wrap');
        if (!page) return Promise.resolve();

        return new Promise(resolve => {
            page.style.animation = `fadeOut ${duration}ms ease forwards`;
            setTimeout(resolve, duration);
        });
    }

    static fadeIn(duration = 300) {
        const page = document.querySelector('.page-wrap');
        if (!page) return;
        page.style.animation = `fadeIn ${duration}ms ease forwards`;
    }
}

class AnimatedCounter {
    constructor(element, target, duration = 1000) {
        this.element = element;
        this.target = parseInt(target);
        this.duration = duration;
        this.current = 0;
        this.increment = this.target / (duration / 16);
    }

    start() {
        const interval = setInterval(() => {
            this.current += this.increment;
            if (this.current >= this.target) {
                this.current = this.target;
                clearInterval(interval);
            }
            this.element.textContent = Math.floor(this.current);
        }, 16);
    }
}

class ProgressRing {
    constructor(element, radius = 45, circumference = null) {
        this.element = element;
        this.radius = radius;
        this.circumference = circumference || radius * 2 * Math.PI;
    }

    setProgress(percent) {
        const offset = this.circumference - (percent / 100) * this.circumference;
        this.element.style.strokeDashoffset = offset;
    }

    animate(fromPercent, toPercent, duration = 1000) {
        const startTime = Date.now();
        const animate = () => {
            const elapsed = Date.now() - startTime;
            const progress = Math.min(elapsed / duration, 1);
            const currentPercent = fromPercent + (toPercent - fromPercent) * progress;
            this.setProgress(currentPercent);

            if (progress < 1) {
                requestAnimationFrame(animate);
            }
        };
        animate();
    }
}

class SmoothScroll {
    static scrollTo(target, duration = 800) {
        const element = typeof target === 'string' 
            ? document.querySelector(target) 
            : target;

        if (!element) return;

        const start = window.scrollY;
        const top = element.getBoundingClientRect().top + start;
        const difference = top - start;
        let startTime = Date.now();

        const scroll = () => {
            let elapsed = Date.now() - startTime;
            window.scrollY = this.easeInOutCubic(elapsed, start, difference, duration);

            if (elapsed < duration) {
                requestAnimationFrame(scroll);
            } else {
                window.scrollTo(0, top);
            }
        };

        requestAnimationFrame(scroll);
    }

    static easeInOutCubic(elapsed, start, distance, duration) {
        elapsed /= duration / 2;
        if (elapsed < 1) return distance / 2 * elapsed * elapsed * elapsed + start;
        elapsed -= 2;
        return distance / 2 * (elapsed * elapsed * elapsed + 2) + start;
    }
}

class Tooltip {
    constructor(element, text, position = 'top') {
        this.element = element;
        this.text = text;
        this.position = position;
        this.tooltip = null;
        this.init();
    }

    init() {
        this.element.addEventListener('mouseenter', () => this.show());
        this.element.addEventListener('mouseleave', () => this.hide());
    }

    show() {
        this.tooltip = document.createElement('div');
        this.tooltip.className = `tooltip-box tooltip-${this.position}`;
        this.tooltip.textContent = this.text;
        this.tooltip.style.opacity = '0';
        document.body.appendChild(this.tooltip);

        const rect = this.element.getBoundingClientRect();
        const tooltipRect = this.tooltip.getBoundingClientRect();

        const positions = {
            'top': {
                left: rect.left + rect.width / 2 - tooltipRect.width / 2,
                top: rect.top - tooltipRect.height - 10
            },
            'bottom': {
                left: rect.left + rect.width / 2 - tooltipRect.width / 2,
                top: rect.bottom + 10
            },
            'left': {
                left: rect.left - tooltipRect.width - 10,
                top: rect.top + rect.height / 2 - tooltipRect.height / 2
            },
            'right': {
                left: rect.right + 10,
                top: rect.top + rect.height / 2 - tooltipRect.height / 2
            }
        };

        const pos = positions[this.position];
        this.tooltip.style.left = pos.left + 'px';
        this.tooltip.style.top = pos.top + 'px';

        setTimeout(() => {
            this.tooltip.style.opacity = '1';
        }, 0);
    }

    hide() {
        if (this.tooltip) {
            this.tooltip.style.opacity = '0';
            setTimeout(() => this.tooltip.remove(), 300);
        }
    }
}

class ExamTimer {
    constructor(containerSelector, totalSeconds) {
        this.container = document.querySelector(containerSelector);
        this.totalSeconds = totalSeconds;
        this.remainingSeconds = totalSeconds;
        this.intervalId = null;
        this.onWarning = null;
        this.onDanger = null;
        this.onExpire = null;
    }

    start() {
        this.intervalId = setInterval(() => {
            this.remainingSeconds--;
            this.updateDisplay();
            this.checkThresholds();

            if (this.remainingSeconds <= 0) {
                this.expire();
            }
        }, 1000);
    }

    updateDisplay() {
        const hours = Math.floor(this.remainingSeconds / 3600);
        const minutes = Math.floor((this.remainingSeconds % 3600) / 60);
        const seconds = this.remainingSeconds % 60;

        const display = `${String(hours).padStart(2, '0')}:${String(minutes).padStart(2, '0')}:${String(seconds).padStart(2, '0')}`;
        if (this.container) {
            this.container.textContent = display;
        }
    }

    checkThresholds() {
        const percent = (this.remainingSeconds / this.totalSeconds) * 100;

        if (percent <= 10 && this.onDanger) {
            this.onDanger();
        } else if (percent <= 25 && this.onWarning) {
            this.onWarning();
        }
    }

    expire() {
        clearInterval(this.intervalId);
        if (this.onExpire) this.onExpire();
    }

    pause() {
        clearInterval(this.intervalId);
    }

    resume() {
        this.start();
    }

    getRemaining() {
        return this.remainingSeconds;
    }
}

class FileUploadDropZone {
    constructor(containerSelector, onFilesSelected) {
        this.container = document.querySelector(containerSelector);
        this.onFilesSelected = onFilesSelected;
        if (this.container) this.init();
    }

    init() {
        this.container.addEventListener('dragover', (e) => this.handleDragOver(e));
        this.container.addEventListener('dragleave', (e) => this.handleDragLeave(e));
        this.container.addEventListener('drop', (e) => this.handleDrop(e));
    }

    handleDragOver(e) {
        e.preventDefault();
        e.stopPropagation();
        this.container.classList.add('drag-active');
    }

    handleDragLeave(e) {
        e.preventDefault();
        e.stopPropagation();
        this.container.classList.remove('drag-active');
    }

    handleDrop(e) {
        e.preventDefault();
        e.stopPropagation();
        this.container.classList.remove('drag-active');
        const files = e.dataTransfer.files;
        if (this.onFilesSelected) this.onFilesSelected(files);
    }
}

// Export for use in other scripts
window.FormValidator = FormValidator;
window.DataTable = DataTable;
window.PageTransition = PageTransition;
window.AnimatedCounter = AnimatedCounter;
window.ProgressRing = ProgressRing;
window.SmoothScroll = SmoothScroll;
window.Tooltip = Tooltip;
window.ExamTimer = ExamTimer;
window.FileUploadDropZone = FileUploadDropZone;
